import{_ as s,W as n,X as a,Y as e}from"./framework-9a5142fa.js";const t={},o=e(`<ul><li><a href="#1-ps1">1. PS1</a><ul><li><a href="#11-usage">1.1. usage</a></li><li><a href="#12-symbol">1.2. Symbol</a></li><li><a href="#13-color">1.3. Color</a></li><li><a href="#14-advance">1.4. Advance</a><ul><li><a href="#141-debian_chroot">1.4.1. debian_chroot</a></li><li><a href="#142-%E5%9C%A8-ps1-%E5%8F%98%E9%87%8F%E4%B8%AD%E4%BD%BF%E7%94%A8-bash-shell-%E5%87%BD%E6%95%B0">1.4.2. 在 PS1 变量中使用 bash shell 函数</a></li><li><a href="#143-%E5%9C%A8-ps1-%E5%8F%98%E9%87%8F%E4%B8%AD%E4%BD%BF%E7%94%A8-shell-%E8%84%9A%E6%9C%AC">1.4.3. 在 PS1 变量中使用 shell 脚本</a></li></ul></li><li><a href="#15-summary">1.5. Summary</a></li></ul></li></ul><hr><h1 id="_1-ps1" tabindex="-1"><a class="header-anchor" href="#_1-ps1" aria-hidden="true">#</a> 1. PS1</h1><h2 id="_1-1-usage" tabindex="-1"><a class="header-anchor" href="#_1-1-usage" aria-hidden="true">#</a> 1.1. usage</h2><p>不建议修改 <code>.bashrc</code>，本地可能好用，但是服务器可能失败。</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code>$ <span class="token function">vim</span> ~/.bashrc
<span class="token builtin class-name">export</span> <span class="token assign-left variable"><span class="token environment constant">PS1</span></span><span class="token operator">=</span><span class="token string">&quot;<span class="token entity" title="\\t">\\t</span> [\\u@\\h \\w]\\$ &quot;</span>

$ <span class="token builtin class-name">source</span> ~/.bashrc
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>修改 <code>.bash_profile</code> or <code>.profile</code> （用户登录shell加载什么）</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token comment"># if running bash</span>
<span class="token keyword">if</span> <span class="token punctuation">[</span> <span class="token parameter variable">-n</span> <span class="token string">&quot;<span class="token environment constant">$BASH_VERSION</span>&quot;</span> <span class="token punctuation">]</span><span class="token punctuation">;</span> <span class="token keyword">then</span>
    <span class="token comment"># include .bashrc if it exists</span>
    <span class="token keyword">if</span> <span class="token punctuation">[</span> <span class="token parameter variable">-f</span> <span class="token string">&quot;<span class="token environment constant">$HOME</span>/.bashrc&quot;</span> <span class="token punctuation">]</span><span class="token punctuation">;</span> <span class="token keyword">then</span>
        <span class="token builtin class-name">.</span> <span class="token string">&quot;<span class="token environment constant">$HOME</span>/.bashrc&quot;</span>
    <span class="token keyword">fi</span>
<span class="token keyword">fi</span>

<span class="token builtin class-name">export</span> <span class="token assign-left variable"><span class="token environment constant">PS1</span></span><span class="token operator">=</span><span class="token string">&quot;<span class="token entity" title="\\t">\\t</span> [\\u@\\h \\w]\\$ &quot;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="_1-2-symbol" tabindex="-1"><a class="header-anchor" href="#_1-2-symbol" aria-hidden="true">#</a> 1.2. Symbol</h2><ul><li><p>时间 <code>\\d</code> ：代表日期，格式为weekday month date，例如：&quot;Mon Aug 1&quot; <code>\\A</code> ：<code>HH:MM</code>，24小时格式 <code>\\t</code> ：<code>HH:MM:SS</code>，24小时格式 <code>\\T</code> ：<code>HH:MM:SS</code>，12小时格式</p></li><li><p>常用信息： <code>\\u</code> ：当前用户的账号名称 <code>\\H</code> ：完整的主机名称。例如：我的机器名称为：<code>fc4.linux</code>，则这个名称就是<code>fc4.linux</code><code>\\h</code> ：仅取主机的第一个名字，如上例，则为<code>fc4</code>，<code>.linux</code>则被省略 <code>\\W</code> ：利用basename取得工作目录名称，所以只会列出最后一个目录 <code>\\w</code> ：完整的工作目录名称。家目录会以 <code>~</code> 代替 <code>\\\\$</code>(<code>\\$</code>显示出来还是<code>$</code>) ：提示字符，如果是root时，提示符为：<code>#</code> ，普通用户则为：<code>$</code></p></li><li><p>其他： <code>\\!</code>: 此命令的历史编号 <code>\\#</code>: 该命令的命令号 <code>\\v</code>: bash 的版本（例如 5.1） <code>\\V</code>: bash 的版本+补丁（例如 5.1.6） <code>\\s</code>: shell的名称，如<code>-bash</code>。 <code>\\n</code>: 换行 <code>\\r</code>: 回到开头 <code>\\[</code>和<code>\\]</code>：表示非打印部分</p></li></ul><p>The default PS1 example:</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code>$ <span class="token assign-left variable"><span class="token environment constant">PS1</span></span><span class="token operator">=</span><span class="token string">&quot;[\\u@\\h \\w]\\$ &quot;</span>
<span class="token punctuation">[</span>admin@kali ~<span class="token punctuation">]</span>$ <span class="token function">ls</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div></div></div><p>带个时间</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code>$ <span class="token assign-left variable"><span class="token environment constant">PS1</span></span><span class="token operator">=</span><span class="token string">&quot;<span class="token entity" title="\\t">\\t</span> [\\u@\\h \\w]\\$ &quot;</span>
<span class="token number">20</span>:52:46 <span class="token punctuation">[</span>admin@kali ~<span class="token punctuation">]</span>$ <span class="token function">ls</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="_1-3-color" tabindex="-1"><a class="header-anchor" href="#_1-3-color" aria-hidden="true">#</a> 1.3. Color</h2><p>设置PS1变量使提示符成为彩色</p><p>Sytax: <code>\\e[F;Bm</code>（或者使用033替换e，即<code>\\033[F;Bm</code>）。但你可能还会见到用<code>\\[</code>和<code>\\]</code>包裹的形式，<code>\\[\\e[F;Bm\\]</code>，这个加括号的才是我们真正使用的。</p><p>因为不用括号包裹的话，当PS1中涉及Color这种非打印字符效果时，会出现一个命令错误缓存显示的问题</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token comment"># 当你打过长命令时</span>
$ <span class="token function">vim</span> hhhhh.txt
$ <span class="token function">ls</span>
<span class="token comment"># 这时你往上翻，会发现长命令的开头还缓存着，显示错误</span>
$ vimls
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>其中<code>F</code>为前景颜色（即字体），<code>B</code>为背景色，即为下表。 注意：表中这些数字都是不重复的，意味着FB的顺序随便。以及，<code>F;B</code>的意思也不是必须有分号，而是有多个F或B的组合（F顶多有一个，B可以有多个）用分号连接的意思，一个F或B就不用分号。</p><table><thead><tr><th>前景F</th><th>背景B</th><th>颜色、效果</th></tr></thead><tbody><tr><td>30</td><td>40</td><td>黑色</td></tr><tr><td>31</td><td>41</td><td>红色</td></tr><tr><td>32</td><td>42</td><td>绿色</td></tr><tr><td>33</td><td>43</td><td>黃色</td></tr><tr><td>34</td><td>44</td><td>蓝色</td></tr><tr><td>35</td><td>45</td><td>紫紅色</td></tr><tr><td>36</td><td>46</td><td>青蓝色</td></tr><tr><td>37</td><td>47</td><td>白色</td></tr><tr><td></td><td>0</td><td>OFF</td></tr><tr><td></td><td>1</td><td>高亮前景色</td></tr><tr><td></td><td>3</td><td>斜体</td></tr><tr><td></td><td>4</td><td>underline</td></tr><tr><td></td><td>5</td><td>闪烁</td></tr><tr><td></td><td>7</td><td>反白显示</td></tr><tr><td></td><td>8</td><td>不可见</td></tr></tbody></table><p>所以：</p><ul><li>开启颜色输出： <ul><li>单个： <ul><li>只有前景<code>\\e[Fm</code>，如绿字<code>\\e[32m</code>。</li><li>只有后景<code>\\e[Bm</code>，如反白显示<code>\\e[8m</code>。</li></ul></li><li>组合 <ul><li>绿字白底<code>\\e[32;47m</code></li><li>绿字白底斜体下划线<code>\\e[32;47;3;4m</code></li></ul></li></ul></li><li>关闭颜色输出：<code>\\e[0m</code>（可以简写为<code>\\e[m</code>）</li></ul><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token comment"># 绿字</span>
$ <span class="token assign-left variable"><span class="token environment constant">PS1</span></span><span class="token operator">=</span><span class="token string">&quot;\\[<span class="token entity" title="\\e">\\e</span>[32m\\][\\u@\\h \\w]$ \\[<span class="token entity" title="\\e">\\e</span>[m\\]&quot;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div></div></div><p><img src="https://cdn.jsdelivr.net/gh/sword4869/pic1@main/images/202406231911570.jpg" alt="green_foreground"></p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token comment"># 反白</span>
$ <span class="token assign-left variable"><span class="token environment constant">PS1</span></span><span class="token operator">=</span><span class="token string">&quot;\\[<span class="token entity" title="\\e">\\e</span>[7m\\][\\u@\\h \\w]$ \\[<span class="token entity" title="\\e">\\e</span>[m\\]&quot;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div></div></div><p><img src="https://cdn.jsdelivr.net/gh/sword4869/pic1@main/images/202406231909271.jpg" alt="anti-white"></p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token comment"># 绿字白底</span>
$ <span class="token assign-left variable"><span class="token environment constant">PS1</span></span><span class="token operator">=</span><span class="token string">&quot;\\[<span class="token entity" title="\\e">\\e</span>[32;47m\\][\\u@\\h \\w]$ \\[<span class="token entity" title="\\e">\\e</span>[m\\]&quot;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div></div></div><p><img src="https://cdn.jsdelivr.net/gh/sword4869/pic1@main/images/202406231911571.jpg" alt="green_foreground_white_background"></p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token comment"># 绿字白底下划线</span>
$ <span class="token assign-left variable"><span class="token environment constant">PS1</span></span><span class="token operator">=</span><span class="token string">&quot;\\[<span class="token entity" title="\\e">\\e</span>[32;47;3;4m\\][\\u@\\h \\w]$ \\[<span class="token entity" title="\\e">\\e</span>[m\\]&quot;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div></div></div><p><img src="https://cdn.jsdelivr.net/gh/sword4869/pic1@main/images/202406231911572.jpg" alt="green_foreground_white_background_it_underline"></p><h2 id="_1-4-advance" tabindex="-1"><a class="header-anchor" href="#_1-4-advance" aria-hidden="true">#</a> 1.4. Advance</h2><h3 id="_1-4-1-debian-chroot" tabindex="-1"><a class="header-anchor" href="#_1-4-1-debian-chroot" aria-hidden="true">#</a> 1.4.1. debian_chroot</h3><p>通常，表示：<code>\${var:+value}</code></p><p>if <code>$var</code> is defined; then use &#39;value&#39;; else do nothing</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code>$ <span class="token assign-left variable">debian_chroot</span><span class="token operator">=</span><span class="token string">&quot;<span class="token variable"><span class="token variable">$(</span><span class="token function">date</span> +%r<span class="token variable">)</span></span>&quot;</span>  
$ <span class="token assign-left variable"><span class="token environment constant">PS1</span></span><span class="token operator">=</span><span class="token string">&quot;<span class="token variable">\${debian_chroot<span class="token operator">:+</span>($debian_chroot)}</span>$ &quot;</span>
<span class="token punctuation">(</span>05:54:07 AM<span class="token punctuation">)</span>$
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="_1-4-2-在-ps1-变量中使用-bash-shell-函数" tabindex="-1"><a class="header-anchor" href="#_1-4-2-在-ps1-变量中使用-bash-shell-函数" aria-hidden="true">#</a> 1.4.2. 在 PS1 变量中使用 bash shell 函数</h3><p>您还可以调用 PS1 中的 bash shell 函数，如下所示。</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code>$ <span class="token keyword">function</span> <span class="token function-name function">httpdcount</span> <span class="token punctuation">{</span>
<span class="token operator">&gt;</span>  <span class="token function">ps</span> aux <span class="token operator">|</span> <span class="token function">grep</span> httpd <span class="token operator">|</span> <span class="token function">grep</span> <span class="token parameter variable">-v</span> <span class="token function">grep</span> <span class="token operator">|</span> <span class="token function">wc</span> <span class="token parameter variable">-l</span>
<span class="token operator">&gt;</span> <span class="token punctuation">}</span>

$ <span class="token assign-left variable"><span class="token environment constant">PS1</span></span><span class="token operator">=</span><span class="token string">&quot;\\u@\\h [<span class="token variable"><span class="token variable">\`</span>httpdcount<span class="token variable">\`</span></span>]&gt; &quot;</span>
ramesh@dev-db <span class="token punctuation">[</span><span class="token number">12</span><span class="token punctuation">]</span><span class="token operator">&gt;</span>
<span class="token punctuation">[</span>注意：这里显示运行的httpd进程总数<span class="token punctuation">]</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="_1-4-3-在-ps1-变量中使用-shell-脚本" tabindex="-1"><a class="header-anchor" href="#_1-4-3-在-ps1-变量中使用-shell-脚本" aria-hidden="true">#</a> 1.4.3. 在 PS1 变量中使用 shell 脚本</h3><p>您还可以调用 PS1 变量内的 shell 脚本。在下面的示例中，计算当前目录的总文件大小的 <code>~/bin/totalfilesize.sh</code> 在 PS1 变量中被调用。</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code>$ <span class="token function">cat</span> ~/bin/totalfilesize.sh

<span class="token keyword">for</span> <span class="token for-or-select variable">filesize</span> <span class="token keyword">in</span> <span class="token variable"><span class="token variable">$(</span><span class="token function">ls</span> <span class="token parameter variable">-l</span> <span class="token builtin class-name">.</span> <span class="token operator">|</span> <span class="token function">grep</span> <span class="token string">&quot;^-&quot;</span> <span class="token operator">|</span> <span class="token function">awk</span> <span class="token string">&#39;{print $5}&#39;</span><span class="token variable">)</span></span>
<span class="token keyword">do</span>
  <span class="token builtin class-name">let</span> <span class="token assign-left variable">totalsize</span><span class="token operator">=</span><span class="token variable">$totalsize</span>+<span class="token variable">$filesize</span>
<span class="token keyword">done</span>
<span class="token builtin class-name">echo</span> <span class="token parameter variable">-n</span> <span class="token string">&quot;<span class="token variable">$totalsize</span>&quot;</span>

$ <span class="token builtin class-name">export</span> <span class="token assign-left variable"><span class="token environment constant">PATH</span></span><span class="token operator">=</span><span class="token environment constant">$PATH</span>:~/bin
$ <span class="token assign-left variable"><span class="token environment constant">PS1</span></span><span class="token operator">=</span><span class="token string">&quot;\\u@\\h [\\<span class="token variable"><span class="token variable">$(</span>totalfilesize.sh<span class="token variable">)</span></span> bytes]&gt; &quot;</span>
ramesh@dev-db <span class="token punctuation">[</span><span class="token number">534</span> bytes<span class="token punctuation">]</span><span class="token operator">&gt;</span> <span class="token builtin class-name">cd</span> /etc/mail
ramesh@dev-db <span class="token punctuation">[</span><span class="token number">167997</span> bytes<span class="token punctuation">]</span><span class="token operator">&gt;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="_1-5-summary" tabindex="-1"><a class="header-anchor" href="#_1-5-summary" aria-hidden="true">#</a> 1.5. Summary</h2><p><code>\\n</code>：换行 <code>\${debian_chroot:+($debian_chroot)}</code>：chroot <code>\\[\\e[47;5m\\]⭕\\[\\e[m\\]</code>：特殊符号 <code>\\t</code>：时间 <code>\\[\\e[32m\\](\\[\\e[m\\]</code>: 绿色( <code>\\[\\e[31;1m\\]\\u@\\h\\[\\e[m\\]</code>: 红色用户@主机 <code>\\[\\e[32m\\])\\[\\e[m\\]</code>: 绿色) <code>-\\[\\e[32m\\][\\[\\e[m\\]</code>: 绿色[ <code>\\[\\e[36;1m\\]\\w\\[\\e[m\\]</code>: 青绿色当前目录 <code>\\[\\e[32m\\]]\\n\\$\\[\\e[m\\] </code>: 绿色]，换行，$，空格</p><p>⏩</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code>$ <span class="token assign-left variable"><span class="token environment constant">PS1</span></span><span class="token operator">=</span><span class="token string">&quot;<span class="token entity" title="\\n">\\n</span><span class="token variable">\${debian_chroot<span class="token operator">:+</span>($debian_chroot)}</span>\\[<span class="token entity" title="\\e">\\e</span>[47;5m\\]⭕\\[<span class="token entity" title="\\e">\\e</span>[m\\] <span class="token entity" title="\\t">\\t</span> \\[<span class="token entity" title="\\e">\\e</span>[32m\\](\\[<span class="token entity" title="\\e">\\e</span>[m\\]\\[<span class="token entity" title="\\e">\\e</span>[31;1m\\]\\u@\\h\\[<span class="token entity" title="\\e">\\e</span>[m\\]\\[<span class="token entity" title="\\e">\\e</span>[32m\\])\\[<span class="token entity" title="\\e">\\e</span>[m\\]-\\[<span class="token entity" title="\\e">\\e</span>[32m\\][\\[<span class="token entity" title="\\e">\\e</span>[m\\]\\[<span class="token entity" title="\\e">\\e</span>[36;1m\\]\\w\\[<span class="token entity" title="\\e">\\e</span>[m\\]\\[<span class="token entity" title="\\e">\\e</span>[32m\\]]<span class="token entity" title="\\n">\\n</span>\\$\\[<span class="token entity" title="\\e">\\e</span>[m\\] &quot;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p><img src="https://cdn.jsdelivr.net/gh/sword4869/pic1@main/images/202406231910641.png" alt="图 4"></p>`,47),l=[o];function i(c,d){return n(),a("div",null,l)}const r=s(t,[["render",i],["__file","PS1.html.vue"]]);export{r as default};
